# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

from flask import Flask, request, redirect, session, url_for
import requests
import json
import base64
import urllib.parse
import secrets
import hashlib

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# Configuration
OIDC_CONFIG = {
    'issuer': 'https://your-oidc-provider.com',
    'client_id': 'your-client-id',
    'client_secret': 'your-client-secret',
    'redirect_uri': 'http://localhost:5000/callback',
    'scope': 'openid profile email'
}

def get_oidc_config():
    return OIDC_CONFIG

def get_authorization_url():
    config = get_oidc_config()
    auth_url = f"{config['issuer']}/authorize"
    
    params = {
        'response_type': 'code',
        'client_id': config['client_id'],
        'redirect_uri': config['redirect_uri'],
        'scope': config['scope'],
        'state': secrets.token_urlsafe(32),
        'nonce': secrets.token_urlsafe(32)
    }
    
    query_string = urllib.parse.urlencode(params)
    return f"{auth_url}?{query_string}"

@app.route('/')
def index():
    return '<a href="/login">Login with OpenID Connect</a>'

@app.route('/login')
def login():
    auth_url = get_authorization_url()
    return redirect(auth_url)

@app.route('/callback')
def callback():
    config = get_oidc_config()
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return "Authorization code not found", 400
    
    # Exchange code for tokens
    token_url = f"{config['issuer']}/token"
    
    token_data = {
        'grant_type': 'authorization_code',
        'client_id': config['client_id'],
        'client_secret': config['client_secret'],
        'code': code,
        'redirect_uri': config['redirect_uri']
    }
    
    response = requests.post(token_url, data=token_data)
    
    if response.status_code != 200:
        return "Failed to exchange code for tokens", 400
    
    token_response = response.json()
    id_token = token_response.get('id_token')
    
    # Decode JWT token
    try:
        payload = id_token.split('.')[1]
        padding = 4 - (len(payload) % 4)
        payload += '=' * padding
        decoded_payload = base64.urlsafe_b64decode(payload)
        user_claims = json.loads(decoded_payload)
    except Exception as e:
        return "Failed to decode ID token", 400
    
    # Store user info in session
    session['user'] = {
        'sub': user_claims.get('sub'),
        'name': user_claims.get('name'),
        'email': user_claims.get('email'),
        'preferred_username': user_claims.get('preferred_username')
    }
    
    return redirect('/dashboard')

@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect('/login')
    
    user = session['user']
    return f"Welcome {user['name']} ({user['email']})!"

@app.route('/logout')
def logout():
    session.clear()
    return redirect('/')

if __name__ == '__main__':
    app.run(debug=True)